inputs.script:
const c=(v)=>{const t=String(v==null?'':v).trim();return /^\{[a-zA-Z0-9_]+\}$/.test(t)?'':t;};
const jid=c(arg0);
const norm=(v)=>(v||'').replace(/ /g,' ').replace(/[ \t]+/g,' ').replace(/\n{3,}/g,'\n\n').trim();
const bt=document.body.innerText||'';
let title=(document.title||'').split(' | ')[0].trim();
if(!title){const h=document.querySelector('h1');title=h?norm(h.innerText):'';}
const compEl=document.querySelector('a[href*="/company/"]');
let company=compEl?norm(compEl.innerText):'';
if(!company){const parts=(document.title||'').split(' | ');company=parts.length>1?parts[1].trim():'';}
const stripQ=(href)=>{if(!href)return '';try{const u=new URL(href,location.origin);return u.origin+u.pathname;}catch(e){return href;}};
const company_url=compEl?stripQ(compEl.getAttribute('href')):'';
let description='';
const m=bt.search(/About the job/i);
if(m>=0){description=norm(bt.slice(m).replace(/^About the job\s*/i,''));}else{description=norm(bt);}
const cuts=[/\nPeople also viewed/i,/\nSimilar jobs/i,/\nMore jobs/i,/\nJobs you may be interested/i,/\nSet alert/i];
for(const re of cuts){const i=description.search(re);if(i>0)description=description.slice(0,i);}
description=description.trim().slice(0,6000);
let meta='';
const ai=bt.search(/About the job/i);
if(ai>0){const head=bt.slice(0,ai);const lines=head.split('\n').map((s)=>norm(s)).filter(Boolean);const ti=lines.indexOf(title);const after=ti>=0?lines.slice(ti+1):lines;meta=after.slice(0,3).join(' · ');}
let apply_type='';
const ab=[...document.querySelectorAll('button,a')].find((b)=>/^(Easy Apply|Apply)$/i.test((b.innerText||'').trim()));
apply_type=ab?norm(ab.innerText):'';
return {job_id:jid,title:title,company:company,company_url:company_url,meta:meta,description:description,apply_type:apply_type,job_url:location.href};
